// Bank represents the bank system that manages accounts.
type Bank struct {
	accounts map[string]int // accountID -> balance
	mu       sync.RWMutex   // Mutex to protect access to the accounts map
}

var (
	ErrAccountNotFound   = errors.New("account not found")
	ErrInsufficientFunds = errors.New("insufficient funds")
	ErrInvalidAmount     = errors.New("invalid amount: amount must be positive")
	ErrAccountExists     = errors.New("account already exists")
)

// NewBank creates and returns a new Bank instance.
func NewBank() *Bank {
	return &Bank{
		accounts: make(map[string]int),
	}
}

// CreateAccount initializes a new account with a given ID and initial balance.
// This operation is protected by a write lock as it modifies the accounts map.
func (b *Bank) CreateAccount(accountID string, initialBalance int) error {
	b.mu.Lock()
	defer b.mu.Unlock()

	if _, exists := b.accounts[accountID]; exists {
		return fmt.Errorf("%w: %s", ErrAccountExists, accountID)
	}
	if initialBalance < 0 {
		return ErrInvalidAmount
	}
	b.accounts[accountID] = initialBalance
	return nil
}

// GetBalance retrieves the balance for a given account ID.
// This operation uses a read lock, allowing multiple concurrent balance checks.
func (b *Bank) GetBalance(accountID string) (int, error) {
	b.mu.RLock() // Acquire a read lock
	defer b.mu.RUnlock() // Release the read lock when done

	balance, ok := b.accounts[accountID]
	if !ok {
		return 0, fmt.Errorf("%w: %s", ErrAccountNotFound, accountID)
	}
	return balance, nil
}

// Deposit adds an amount to the specified account.
// This operation uses a write lock, ensuring exclusive access during the update.
func (b *Bank) Deposit(accountID string, amount int) error {
	if amount <= 0 {
		return ErrInvalidAmount
	}

	b.mu.Lock() // Acquire a write lock
	defer b.mu.Unlock() // Release the write lock when done

	if _, ok := b.accounts[accountID]; !ok {
		return fmt.Errorf("%w: %s", ErrAccountNotFound, accountID)
	}

	b.accounts[accountID] += amount
	return nil
}

// Withdraw subtracts an amount from the specified account.
// This operation uses a write lock, ensuring exclusive access during the update.
// It also checks for sufficient funds before proceeding.
func (b *Bank) Withdraw(accountID string, amount int) error {
	if amount <= 0 {
		return ErrInvalidAmount
	}

	b.mu.Lock() // Acquire a write lock
	defer b.mu.Unlock() // Release the write lock when done

	balance, ok := b.accounts[accountID]
	if !ok {
		return fmt.Errorf("%w: %s", ErrAccountNotFound, accountID)
	}

	if balance < amount {
		return fmt.Errorf("%w for account %s: current balance %d, requested %d", ErrInsufficientFunds, accountID, balance, amount)
	}

	b.accounts[accountID] -= amount
	return nil
}

